woodmartThemeModule.trackProductViewed=function(){if("visible"===document.visibilityState){var e=document.querySelector(".single-product-page"),t="woodmart_recently_viewed_products",o=parseInt(woodmart_settings.max_recently_viewed_products,10);if(e&&"undefined"!=typeof Cookies){var i=e.id.replace("product-",""),r=Cookies.get(t);if(r){var d=(r=r.split("|")).indexOf(i);-1!==d&&r.splice(d,1),r.unshift(i),r.length>o&&(r=r.slice(0,o)),r=r.join("|")}else r=i;Cookies.set(t,r,{expires:parseInt(woodmart_settings.cookie_expires,10),path:woodmart_settings.cookie_path,secure:woodmart_settings.cookie_secure_param})}}},window.addEventListener("load",function(){woodmartThemeModule.trackProductViewed()});